import '../lib/patch.dart';
import '../lib/profile_store.dart';

void require(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final decoded = ProfilePatch.fromJson({'displayName': null});
  require(decoded.displayName.isPresent, 'explicit null was decoded as absent');
  require(decoded.displayName.value == null, 'clear value was not null');

  final store = ProfileStore(
    const Profile(displayName: 'Ada', note: 'On call'),
  );
  store.apply(
    const ProfilePatch(
      displayName: PatchField<String>.present(null),
      note: PatchField<String>.absent(),
    ),
  );
  require(store.current.displayName == null, 'explicit clear was not applied');
  require(store.current.note == 'On call', 'absent note was changed');
}
